import sys

def main():
    n, m = map(int, input().split())
    a = [0] * m
    b = [0] * m
    for i in range(m):
        a[i], b[i] = map(int, input().split())

    # 辺の数を数える
    edges = [0] * (n + 1)
    for i in range(m):
        edges[a[i]] += 1
        edges[b[i]] += 1

    # 辺の数が奇数の頂点の数を数える
    odd = 0
    for i in range(1, n + 1):
        if edges[i] % 2 == 1:
            odd += 1

    # 辺の数が奇数の頂点の数が 0 か 2 であれば、すべての辺を削除することで、すべての要求を満たすことができる
    # 辺の数が奇数の頂点の数が 1 であれば、すべての辺を削除することはできない
    # その他の場合は、すべての辺を削除することはできない
    if odd == 0 or odd == 2:
        print(0)
    else:
        print(1)

if __name__ == "__main__":
    main()
